            f[i] = f[i - 1] + f[i - 2]

        ans, last_seen = 0, 0
        for i in range(MAX_BITS - 1, -1, -1):
            if (n >> i) & 1:
                ans += f[i]
                if last_seen:
                    return ans
                last_seen = 1
            else:
                last_seen = 0
        return ans + 1
